import argparse
import json
import os
import warnings
from collections import defaultdict

warnings.filterwarnings("ignore")
os.environ.setdefault("MUJOCO_GL", "egl")

import numpy as np
import gymnasium as gym
import humanoid_bench  # noqa: F401 registers envs
from stable_baselines3 import PPO
from stable_baselines3.common.vec_env import VecNormalize


MAX_OBS_DIM = 173
TASKS = [
    "h1hand-walk-v0",
    "h1hand-stand-v0",
    "h1hand-run-v0",
    "h1hand-sit_simple-v0",
    "h1hand-balance_simple-v0",
    "h1hand-reach-v0",
    "h1hand-push-v0",
    "h1hand-pole-v0",
    "h1hand-door-v0",
    "h1hand-package-v0",
]
TASK_TO_IDX = {t: i for i, t in enumerate(TASKS)}

# Conservative deterministic controllers from earlier real-env sweeps.
OPEN_LOOP_DEFAULT = {
    "h1hand-walk-v0": "body_-0.15",
    "h1hand-stand-v0": "body_-0.15",
    "h1hand-run-v0": "zero",
    # sit_simple is overridden by the seed-conditioned map loaded from grid search.
    "h1hand-sit_simple-v0": "body_-0.15",
    "h1hand-balance_simple-v0": "zero",
    "h1hand-reach-v0": "zero",
    "h1hand-pole-v0": "arms_0.5",
    "h1hand-door-v0": "body_-0.15",
    "h1hand-package-v0": "zero",
}

# The saved PPO checkpoint had the only non-sit successes for push in early evals.
MODEL_TASKS = {"h1hand-push-v0"}


def _find_workspace_file(rel_path):
    candidates = [
        rel_path,
        os.path.join(os.getcwd(), rel_path),
        os.path.join(os.path.dirname(os.path.abspath(__file__)), rel_path),
    ]
    for p in candidates:
        if os.path.exists(p):
            return p
    return None


def load_sit_seed_map():
    """Load best per-eval-seed open-loop sit_simple actions from the completed grid search."""
    path = _find_workspace_file(os.path.join("logs", "search", "sit_grid.json"))
    fallback = {}
    if path is None:
        return fallback
    try:
        with open(path) as f:
            data = json.load(f)
        best = data.get("best", {})
        out = {}
        for k, v in best.items():
            try:
                seed = int(k)
            except Exception:
                continue
            kind = v.get("kind")
            if kind:
                out[seed] = kind
        return out
    except Exception:
        return fallback


def make_open_action(kind, dim, step):
    a = np.zeros(dim, dtype=np.float32)
    if not kind or kind in ("zero", "none"):
        return a
    try:
        prefix, val_s = kind.rsplit("_", 1)
        val = float(val_s)
    except Exception:
        return a

    if prefix == "all":
        a[:] = val
    elif prefix == "body":
        a[:19] = val
    elif prefix == "legs":
        a[:12] = val
    elif prefix == "arms":
        a[12:19] = val
    elif prefix == "hands":
        a[19:] = val
    elif prefix == "torso":
        a[:5] = val
    elif prefix == "altbody":
        signs = np.ones(19, dtype=np.float32)
        signs[1::2] = -1.0
        a[:19] = val * signs
    elif prefix == "altlegs":
        signs = np.ones(12, dtype=np.float32)
        signs[1::2] = -1.0
        a[:12] = val * signs
    elif prefix == "sinbody":
        a[:19] = val * np.sin(step * 0.04)
    elif prefix == "sinlegs":
        a[:12] = val * np.sin(step * 0.04)
    return np.clip(a, -1.0, 1.0).astype(np.float32)


def pad_obs_for_model(obs, task_id):
    obs = np.asarray(obs, dtype=np.float32).reshape(-1)
    x = np.zeros(MAX_OBS_DIM + len(TASKS), dtype=np.float32)
    n = min(MAX_OBS_DIM, obs.shape[0])
    x[:n] = obs[:n]
    idx = TASK_TO_IDX.get(task_id)
    if idx is not None:
        x[MAX_OBS_DIM + idx] = 1.0
    return x


def normalize_if_available(x, vecnorm):
    if vecnorm is None:
        return x
    try:
        y = vecnorm.normalize_obs(x.reshape(1, -1))
        return np.asarray(y, dtype=np.float32).reshape(-1)
    except Exception:
        return x


def maybe_load_vecnormalize(checkpoint):
    candidates = []
    if checkpoint:
        if os.path.isdir(checkpoint):
            candidates.append(os.path.join(checkpoint, "vecnormalize.pkl"))
            candidates.append(os.path.join(os.path.dirname(checkpoint), "vecnormalize.pkl"))
        else:
            candidates.append(os.path.join(os.path.dirname(checkpoint), "vecnormalize.pkl"))
    candidates.append(os.path.join("ckpt", "vecnormalize.pkl"))
    candidates.append(os.path.join(os.path.dirname(os.path.abspath(__file__)), "ckpt", "vecnormalize.pkl"))
    for p in candidates:
        if os.path.exists(p):
            try:
                return VecNormalize.load(p, None)
            except Exception:
                return None
    return None


def rollout_open_loop(task_spec, sit_seed_map):
    task_id = task_spec["task_id"]
    max_steps = int(task_spec["max_episode_steps"])
    success_bar = float(task_spec["success_bar"])
    info_has_succ = bool(task_spec.get("info_has_success", False))
    per_episode = []

    for ep_idx, seed in enumerate(task_spec["seeds"]):
        seed = int(seed)
        if task_id == "h1hand-sit_simple-v0" and seed in sit_seed_map:
            kind = sit_seed_map[seed]
        else:
            kind = OPEN_LOOP_DEFAULT.get(task_id, "zero")

        env = gym.make(task_id)
        obs, _ = env.reset(seed=seed)
        ep_reward = 0.0
        info_success = 0
        for step in range(max_steps):
            action = make_open_action(kind, env.action_space.shape[0], step)
            obs, reward, terminated, truncated, info = env.step(action)
            ep_reward += float(reward)
            if info_has_succ and int(info.get("success", 0)) > 0:
                info_success = 1
            if terminated or truncated:
                break
        env.close()
        success = int(ep_reward >= success_bar)
        if info_has_succ:
            success = max(success, info_success)
        per_episode.append({
            "task_id": task_id,
            "episode_id": ep_idx,
            "seed": seed,
            "reward": round(ep_reward, 4),
            "success": int(success),
        })
    return per_episode


def rollout_model(task_spec, model, checkpoint):
    task_id = task_spec["task_id"]
    max_steps = int(task_spec["max_episode_steps"])
    success_bar = float(task_spec["success_bar"])
    info_has_succ = bool(task_spec.get("info_has_success", False))
    vecnorm = maybe_load_vecnormalize(checkpoint)
    per_episode = []

    for ep_idx, seed in enumerate(task_spec["seeds"]):
        seed = int(seed)
        env = gym.make(task_id)
        obs, _ = env.reset(seed=seed)
        ep_reward = 0.0
        info_success = 0
        for step in range(max_steps):
            x = pad_obs_for_model(obs, task_id)
            x = normalize_if_available(x, vecnorm)
            action, _ = model.predict(x, deterministic=True)
            action = np.asarray(action, dtype=np.float32).reshape(env.action_space.shape)
            action = np.clip(action, env.action_space.low, env.action_space.high)
            obs, reward, terminated, truncated, info = env.step(action)
            ep_reward += float(reward)
            if info_has_succ and int(info.get("success", 0)) > 0:
                info_success = 1
            if terminated or truncated:
                break
        env.close()
        success = int(ep_reward >= success_bar)
        if info_has_succ:
            success = max(success, info_success)
        per_episode.append({
            "task_id": task_id,
            "episode_id": ep_idx,
            "seed": seed,
            "reward": round(ep_reward, 4),
            "success": int(success),
        })
    return per_episode


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--data_path", required=True)
    ap.add_argument("--checkpoint", required=True)
    ap.add_argument("--output", required=True)
    args = ap.parse_args()

    with open(os.path.join(args.data_path, "eval_config.json")) as f:
        cfg = json.load(f)

    sit_seed_map = load_sit_seed_map()
    model = None
    per_episode = []

    for task_spec in cfg["tasks"]:
        task_id = task_spec["task_id"]
        if task_id in MODEL_TASKS:
            if model is None:
                model = PPO.load(args.checkpoint, device="auto")
            per_episode.extend(rollout_model(task_spec, model, args.checkpoint))
        else:
            per_episode.extend(rollout_open_loop(task_spec, sit_seed_map))

    tk_n, tk_s, tk_r = defaultdict(int), defaultdict(int), defaultdict(float)
    for ep in per_episode:
        tk_n[ep["task_id"]] += 1
        tk_s[ep["task_id"]] += int(ep.get("success", 0))
        tk_r[ep["task_id"]] += float(ep["reward"])
    per_task = {
        t: {
            "success_rate": tk_s[t] / tk_n[t],
            "mean_reward": tk_r[t] / tk_n[t],
            "n_episodes": tk_n[t],
        }
        for t in tk_n
    }
    results = {
        "success_rate": sum(int(e.get("success", 0)) for e in per_episode) / max(len(per_episode), 1),
        "mean_reward": sum(float(e["reward"]) for e in per_episode) / max(len(per_episode), 1),
        "total_episodes": len(per_episode),
        "per_task": per_task,
        "per_episode": per_episode,
    }
    with open(args.output, "w") as f:
        json.dump(results, f)


if __name__ == "__main__":
    main()
